import { AgentContext, WorkflowStep } from 'mastra';

type ValidMemory = {
  conversationId: string;
  timestamp: number;
  userIntent: string;
  toolOutputs: Array<{name: string; data: unknown}>;
};

function detectMemorySchemaIssues(ctx: AgentContext): boolean {
  const memory = ctx.memory.get('session') as unknown;

  if (!isValidMemorySchema(memory)) {
    console.error('❌ Memory schema violation:', validateMemorySchema(memory));
    return true; // Issue detected
  }
  return false;
}

function isValidMemorySchema(data: unknown): data is ValidMemory {
  return typeof data === 'object' && data !== null &&
    'conversationId' in data && typeof (data as any).conversationId === 'string' &&
    'timestamp' in data && typeof (data as any).timestamp === 'number';
}

// Hook into Mastra workflow
const step: WorkflowStep = {
  name: 'validateMemory',
  execute: async (ctx) => {
    if (detectMemorySchemaIssues(ctx)) {
      throw new Error('Memory validation failed');
    }
  }
};

import { AgentContext } from 'mastra';

function detectStaleContext(ctx: AgentContext): Array<string> {
  const issues: string[] = [];
  const now = Date.now();
  const SESSION_THRESHOLD = 5 * 60 * 1000; // 5 minutes

  ctx.memory.entries().forEach(([key, entry]) => {
    if (typeof entry.timestamp === 'number' && 
        now - entry.timestamp > SESSION_THRESHOLD) {
      issues.push(`Stale memory key: ${key} (age: ${(now - entry.timestamp) / 1000}s)`);
    }
  });

  return issues;
}

// Usage in Mastra agent hook
async function auditMemoryBeforeStep(ctx: AgentContext) {
  const staleIssues = detectStaleContext(ctx);
  if (staleIssues.length > 0) {
    console.warn('🚨 Stale context detected:', staleIssues);
    // Clear stale entries
    staleIssues.forEach(issue => {
      const key = issue.match(/key: (\w+)/)?.[1];
      key && ctx.memory.delete(key);
    });
  }
}

import { AgentContext, ToolCallResult } from 'mastra';

function detectMalformedToolOutputs(ctx: AgentContext): boolean {
  const toolResults = ctx.memory.get('toolCalls') as ToolCallResult[] | undefined;

  if (!toolResults?.length) return false;

  for (const result of toolResults) {
    try {
      if (result.output && typeof result.output === 'string') {
        JSON.parse(result.output);
      }
    } catch (e) {
      console.error(`❌ Malformed tool output from ${result.toolName}:`, result.output);
      return true; // Issue detected
    }
  }

  return false;
}

// Mastra workflow guard
const memoryGuard: WorkflowStep = {
  name: 'checkToolOutputs',
  execute: async (ctx: AgentContext) => {
    if (detectMalformedToolOutputs(ctx)) {
      ctx.memory.set('toolCalls', []);
      throw new Error('Tool output validation failed - cleared memory');
    }
  }
};

