import { AgentContext, Middleware } from 'mastra';

type SafeMemory = {
  conversationId: string;
  context: Record<string, unknown>;
  timestamp: number;
};

const memoryValidationMiddleware: Middleware = {
  async beforeStep(ctx: AgentContext, next) {
    const rawMemory = ctx.memory.get('session');
    const safeMemory = sanitizeMemory(rawMemory);

    ctx.memory.set('session', safeMemory);
    await next();
  }
};

function sanitizeMemory(raw: unknown): SafeMemory {
  const now = Date.now();
  const safe: SafeMemory = {
    conversationId: typeof raw === 'object' && raw !== null 
      ? String((raw as any).conversationId || 'unknown')
      : 'unknown',
    context: {},
    timestamp: now
  };

  // Safely extract context
  if (typeof raw === 'object' && raw !== null) {
    safe.context = pickSafeFields(raw as Record<string, unknown>);
  }

  return safe;
}

function pickSafeFields(obj: Record<string, unknown>): Record<string, unknown> {
  const safeFields = {};
  for (const [key, value] of Object.entries(obj)) {
    if (isSafeValue(value)) {
      safeFields[key] = value;
    }
  }
  return safeFields;
}

function isSafeValue(value: unknown): boolean {
  return typeof value !== 'function' &&
         value !== null &&
         typeof value !== 'symbol';
}

import { AgentContext, WorkflowHook } from 'mastra';

const MEMORY_TTL = 10 * 60 * 1000; // 10 minutes

const ttlMemoryHook: WorkflowHook = {
  async beforeExecute(ctx: AgentContext) {
    await enforceMemoryTTL(ctx);
  }
};

async function enforceMemoryTTL(ctx: AgentContext) {
  const now = Date.now();
  const expiredKeys: string[] = [];

  ctx.memory.entries().forEach(([key, entry]) => {
    if (typeof entry.timestamp === 'number' && 
        now - entry.timestamp > MEMORY_TTL) {
      expiredKeys.push(key);
    }
  });

  for (const key of expiredKeys) {
    ctx.memory.delete(key);
    console.log(`🧹 Expired memory: ${key}`);
  }
}

// Register in Mastra agent
const agentConfig = {
  hooks: {
    beforeExecute: [ttlMemoryHook]
  }
};

import { ToolResult, AgentContext } from 'mastra';

function wrapToolResponse(result: ToolResult): ToolResult {
  return {
    ...result,
    output: serializeSafely(result.output),
    validated: true,
    timestamp: Date.now()
  };
}

function serializeSafely(data: unknown): string {
  try {
    // Convert to JSON-safe structure
    const safeData = convertToSafeObject(data);
    return JSON.stringify(safeData);
  } catch (error) {
    console.warn('Tool output serialization failed, using fallback:', error);
    return JSON.stringify({ error: 'Serialization failed', rawType: typeof data });
  }
}

function convertToSafeObject(data: unknown): unknown {
  if (data === null || typeof data === 'string' || typeof data === 'number' || typeof data === 'boolean') {
    return data;
  }

  if (Array.isArray(data)) {
    return data.map(convertToSafeObject);
  }

  if (typeof data === 'object') {
    const obj = data as Record<string, unknown>;
    const safe: Record<string, unknown> = {};
    for (const [key, value] of Object.entries(obj)) {
      safe[key] = convertToSafeObject(value);
    }
    return safe;
  }

  return String(data);
}

// Mastra tool wrapper
const safeTool = {
  ...originalTool,
  execute: async (input) => {
    const result = await originalTool.execute(input);
    return wrapToolResponse(result);
  }
};

