import { Vex } from '@vex_dev/sdk';
import { AgentContext, MastraAgent } from 'mastra';

const vex = new Vex({
  projectId: 'your-project-id',
  agentMemoryGuard: {
    schemas: {
      session: {
        conversationId: 'string',
        timestamp: 'number',
        context: 'object'
      }
    },
    ttlMs: 10 * 60 * 1000,
    maxContextSize: 10000
  }
});

// Install Vex middleware in Mastra pipeline
const agent = new MastraAgent({
  middleware: [
    vex.middleware({
      onMemoryViolation: async (issue, ctx: AgentContext) => {
        // Auto-remediate
        ctx.memory.set('session', vex.sanitizeMemory(ctx.memory.get('session')));

        // Log to Vex dashboard
        await vex.track('memory_fixed', {
          workflowId: ctx.workflow.id,
          issueType: issue.type,
          sizeBefore: issue.sizeBefore,
          sizeAfter: ctx.memory.size
        });
      }
    })
  ],
  hooks: {
    beforeStep: [vex.auditMemory],
    afterToolCall: [vex.validateToolOutput]
  }
});

// Vex auto-generates this monitoring query
vex.monitor('memory-health', {
  query: 'memory.schema_violations > 0 OR memory.stale_entries > 5',
  action: 'auto_sanitize',
  alert: {
    slack: '#ai-ops',
    severity: 'critical'
  }
});
